import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const TimbangMuat = () => {
  const navigate = useNavigate();

  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);
  const [list, setList] = useState([]);

  // 🔥 mode otomatis: BRUTO atau TARA
  const [mode, setMode] = useState("BRUTO");

  const [form, setForm] = useState({
    itemType: "",
    no_palka: "",
    bruto_belawan: "",
    tara_belawan: "",
  });

  // ================= RFID =================
  const fetchRFID = useCallback(async () => {
    try {
      setLoading(true);

      const res = await axios.get("http://localhost:5000/api/rfid/latest");
      const truckData = res.data?.truck;

      if (truckData?.truckId) {
        setTruck(truckData);
        await checkBruto(truckData.truckId);
        fetchData(truckData.truckId);
      } else {
        setTruck(null);
      }
    } catch (err) {
      console.error("RFID ERROR:", err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!truck) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [truck, fetchRFID]);

  // ================= CEK BRUTO (PENTING) =================
  const checkBruto = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/loadings/bruto/${truckId}`
      );

      if (res.data) {
        setMode("TARA"); // sudah ada bruto → masuk tahap tara
        setForm((prev) => ({
          ...prev,
          itemType: res.data.itemType,
          no_palka: res.data.no_palka,
        }));
      } else {
        setMode("BRUTO"); // belum ada bruto
      }
    } catch (err) {
      setMode("BRUTO");
    }
  };

  // ================= HANDLE INPUT =================
  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

    // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const truckId = truck?.truckId;

    if (!truckId) {
      alert("RFID belum terbaca!");
      return;
    }

    try {
      // ================= MODE BRUTO =================
      if (mode === "BRUTO") {
        if (!form.itemType || !form.no_palka || !form.bruto_belawan) {
          alert("Item, No Palka, dan Bruto wajib diisi");
          return;
        }

        const payload = {
          truckId,
          itemType: form.itemType,
          no_palka: form.no_palka,
          bruto_belawan: Number(form.bruto_belawan),
          unit: "kg",
        };

        await axios.post("http://localhost:5000/api/loadings", payload);

        alert("Bruto berhasil disimpan");

        setForm({
          itemType: "",
          no_palka: "",
          bruto_belawan: "",
          tara_belawan: "",
        });

        // setelah simpan → langsung masuk mode TARA
        await checkBruto(truckId);
        fetchData(truckId);
      }

      // ================= MODE TARA =================
      else if (mode === "TARA") {
        if (!form.tara_belawan) {
          alert("Tara wajib diisi");
          return;
        }

        const payload = {
          tara_belawan: Number(form.tara_belawan),
        };

        await axios.put(
          `http://localhost:5000/api/loadings/tara/${truckId}`,
          payload
        );

        alert("Tara berhasil disimpan (SELESAI)");

        setForm({
          itemType: "",
          no_palka: "",
          bruto_belawan: "",
          tara_belawan: "",
        });

        setMode("BRUTO"); // reset siklus
        fetchData(truckId);
      }
    } catch (err) {
      console.error("ERROR:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Gagal proses timbang");
    }
  };

  // ================= FETCH DATA =================
  const fetchData = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/loadings/${truckId}`
      );
      setList(res.data || []);
    } catch (err) {
      console.error("FETCH ERROR:", err);
    }
  };

  // ================= UI =================
  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-blue-100 to-white">

      <h1 className="text-3xl font-bold text-center mb-2">
        ⚖️ Timbang Muat Belawan System
      </h1>

      <p className="text-center mb-6 font-semibold">
        Mode: {mode === "BRUTO" ? "INPUT BRUTO" : "INPUT TARA"}
      </p>

      {loading && (
        <div className="flex justify-center">
          <div className="animate-spin w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full"></div>
        </div>
      )}

      {!truck && !loading && (
        <p className="text-center text-gray-600">Menunggu RFID...</p>
      )}

      {truck && (
        <div className="max-w-6xl mx-auto bg-white p-6 shadow rounded">

          {/* INFO TRUCK */}
          <div className="mb-6 grid grid-cols-2 gap-4">
            <div><b>Truck:</b> {truck.truckId}</div>
            <div><b>Driver:</b> {truck.driver}</div>
            <div><b>Tipe:</b> {truck.truckType}</div>
          </div>

          {/* FORM */}
          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

            <input
              name="itemType"
              placeholder="Item"
              value={form.itemType}
              onChange={handleChange}
              className="border p-2"
              disabled={mode === "TARA"}
              required
            />

            <input
              name="no_palka"
              placeholder="No Palka"
              value={form.no_palka}
              onChange={handleChange}
              className="border p-2"
              disabled={mode === "TARA"}
              required
            />

            {mode === "BRUTO" && (
              <input
                name="bruto_belawan"
                type="number"
                placeholder="Bruto"
                value={form.bruto_belawan}
                onChange={handleChange}
                className="border p-2"
                required
              />
            )}

            {mode === "TARA" && (
              <input
                name="tara_belawan"
                type="number"
                placeholder="Tara"
                value={form.tara_belawan}
                onChange={handleChange}
                className="border p-2"
                required
              />
            )}

            {/* NETTO PREVIEW */}
            <div className="border p-2 bg-gray-100">
              Netto Preview:{" "}
              {mode === "BRUTO"
                ? 0
                : Number(form.bruto_belawan || 0) -
                  Number(form.tara_belawan || 0)}
            </div>

            <button
              type="submit"
              className="col-span-2 bg-blue-600 text-white p-2"
            >
              {mode === "BRUTO" ? "Simpan Bruto" : "Simpan Tara"}
            </button>

          </form>

          {/* TABLE */}
          <div className="mt-10">
            <table className="w-full border text-sm">
              <thead className="bg-blue-200">
                <tr>
                  <th>Item</th>
                  <th>No Palka</th>
                  <th>Bruto</th>
                  <th>Tara</th>
                  <th>Netto</th>
                  <th>Status</th>
                </tr>
              </thead>

              <tbody>
                {list.map((item, i) => (
                  <tr key={i}>
                    <td>{item.itemType}</td>
                    <td>{item.no_palka}</td>
                    <td>{item.bruto_belawan}</td>
                    <td>{item.tara_belawan}</td>
                    <td className="font-bold">{item.netto_belawan}</td>
                    <td>{item.status_timbang}</td>
                  </tr>
                ))}

                {list.length === 0 && (
                  <tr>
                    <td colSpan="6" className="text-center p-4">
                      Belum ada data
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

        </div>
      )}
    </div>
  );
};

export default TimbangMuat;
